      expect(plan.baseZoom, 1e12);
      expect(plan.peakZoom, 1e11);
      expect(plan.floorZoom, 1e11);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 1e11);
      expect(
